INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-6f0ba476-moex-00010', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司某商品存貨成本為$8,000，於X5年底淨變現價值為$7,800，重置成本為$7,700，淨變現價 值減正常利潤為$7,750，則X5年底該商品存貨帳面金額應為何？', '["$8,000", "$7,800", "$7,750", "$7,700"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "ce01bf289bb9", "answer_pdf_sha1": "5b09b4b6231a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00011', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '乙公司X1年底流通在外的股本包括面額$100、10,000股6%之特別股，及100,000股面額$10的 普通股，並有保留盈餘$800,000。X1年公司宣告發放現金股利$400,000給特別股與普通股。假設 特別股為累積、完全參加、積欠兩年股利，則 X1 年特別股與普通股分別可以領到之現金股利金 額為多少？', '["$120,000與$280,000", "$230,000與$170,000", "$250,000與$150,000", "$260,000與$140,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "ce01bf289bb9", "answer_pdf_sha1": "5b09b4b6231a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00012', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於X5年1月1日購入機器設備一台，購買成本為$2,000,000，預計使用5年，估計殘值為 $200,000，採用雙倍數餘額遞減法提列折舊，則X6年度應提列多少折舊費用？', '["$360,000", "$480,000", "$560,000", "$630,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "ce01bf289bb9", "answer_pdf_sha1": "5b09b4b6231a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00013', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於X3年初以總成本$450,000購入機器設備一台，預計使用4年，殘值為$50,000，採用直 線法提列折舊。X5年初對該機器設備投入了重大改良支出$100,000，該支出並可使機器之使用年 限延長1年，殘值仍為$50,000，且自X5年起改採用年數合計法提列折舊。則甲公司於X5年底 針對該機器設備應提列多少折舊費用？', '["$100,000", "$125,000", "$150,000", "$175,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "ce01bf289bb9", "answer_pdf_sha1": "5b09b4b6231a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00014', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於 X4 年初將採用成本模式衡量且帳面金額為$8,000,000 之辦公大樓，轉換為採公允價值 模式之投資性不動產，該辦公大樓X4年初與X4年底之公允價值分別為$9,000,000與$9,900,000。 若不考慮所得稅影響，則甲公司於X4年底應認列公允價值變動利益為多少？', '["$900,000", "$1,000,000", "$1,900,000", "$2,900,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "ce01bf289bb9", "answer_pdf_sha1": "5b09b4b6231a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00015', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '處分損益當作當期損益、不必作期末評價、手續費列入取得成本之中、不必攤銷折價或溢價，以 上若依IFRS9金融工具分類為「按攤銷後成本衡量之金融資產」投資，則正確的敘述有幾項？', '["1項", "2項", "3項", "4項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "ce01bf289bb9", "answer_pdf_sha1": "5b09b4b6231a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00016', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於X3年1月1日，以每股$75買入乙公司股票10,000股，手續費$800，共支付$750,800。 甲公司將該股票投資原始指定為「透過其他綜合損益按公允價值衡量之金融資產」。X3 年 12 月 31日乙公司股票收盤價為$80，X3年配發每股現金股利$3。則有關該金融資產對甲公司X3年度 綜合損益之影響應為何？', '["本期損益增加$0、其他綜合損益增加$30,000", "本期損益增加$0、其他綜合損益增加$49,200", "本期損益增加$30,000、其他綜合損益增加$49,200", "本期損益增加$30,000、其他綜合損益增加$30,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "ce01bf289bb9", "answer_pdf_sha1": "5b09b4b6231a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00017', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司 X1 年度銷貨淨額$32,000,000（假設全部為賒銷），銷貨成本$10,000,000，平均應收帳款 $8,000,000，平均存貨$2,000,000，一年以360天計算，則X1年度甲公司的營業循環為幾天？', '["136", "148", "154", "162"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "ce01bf289bb9", "answer_pdf_sha1": "5b09b4b6231a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00018', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司X1年底有關資料如下：10%累積特別股，每股面額$10，總面額$675,000、普通股，每股 面額$10，總股本$4,000,000、稅前淨利$2,500,000、所得稅率20%、年底普通股每股市價$49，若 甲公司當年度流通在外股數並無變動，則每股盈餘與本益比各為多少？', '["每股盈餘為$4.83、本益比為10.14", "每股盈餘為$5.07、本益比為9.68", "每股盈餘為$6.15、本益比為8.52", "每股盈餘為$7.24、本益比為7.03"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "ce01bf289bb9", "answer_pdf_sha1": "5b09b4b6231a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00019', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司以每股$57出售面額$10之庫藏股6,000股。若庫藏股的成本為每股$46，則此出售分錄應為：', '["借記：現金$276,000；貸記：普通股股本$60,000、資本公積－庫藏股交易$216,000", "借記：現金$276,000；貸記：庫藏股$60,000、資本公積－庫藏股交易$216,000", "借記：現金$342,000；貸記：普通股股本$276,000、資本公積－庫藏股交易$66,000", "借記：現金$342,000；貸記：庫藏股$276,000、資本公積－庫藏股交易$66,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:52+00:00", "source_pdf_sha1": "ce01bf289bb9", "answer_pdf_sha1": "5b09b4b6231a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
